proof_block:
// The function returns `()`, so `r1 == r2` is trivial. The real work is
// showing `post1_self_` and `post2_self_` agree on the components named in
// `det_new_proc_with_endpoint_iommu_equal`: root_container, the four perm
// maps (container_perms, process_perms, thread_perms, endpoint_perms), and
// cpu_list. Both posts are pinned by the same ensures clauses against the
// shared `pre_self_`, so we triangulate every component via `pre_self_`.

let oc = pre_self_.get_thread(thread_ptr).owning_container;
let ep_ptr = pre_self_.get_endpoint_ptr_by_endpoint_idx(thread_ptr, endpoint_index).unwrap();

// --- Domain equalities for the four perm maps. -------------------------
// `proc_dom() == process_perms@.dom()`, etc., are all #[verifier(inline)],
// so the ensures give us:
//   post1.container_perms@.dom() == pre.container_perms@.dom()
//   post1.process_perms@.dom() == pre.process_perms@.dom().insert(page_ptr_1)
//   post1.thread_perms@.dom() == pre.thread_perms@.dom().insert(page_ptr_2)
//   post1.endpoint_perms@.dom() == pre.endpoint_perms@.dom()
// and the same for post2. So the post1 / post2 doms must coincide.
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom());

// --- Quota functional uniqueness on `oc`. ------------------------------
// `spec_subtract_mem_4k` is functional in (pre, k): the helper lemma
// collapses both posts to the same quota.
lemma_spec_subtract_mem_4k_functional(
    pre_self_.get_container(oc).quota,
    2,
    post1_self_.get_container(oc).quota,
    post2_self_.get_container(oc).quota,
);
assert(post1_self_.get_container(oc).quota == post2_self_.get_container(oc).quota);

// --- Threads: every pre-thread is preserved across both runs. ----------
// The ensures use `#![trigger pre_self_.get_thread(t_ptr)]`, which is the
// same atom for post1 and post2, so re-firing on that trigger lines them
// up.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr)
         && post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr)
         && post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
}

// `thread_ptr` is in pre's domain by the requires clause; both posts agree
// on its owning_container.
assert(pre_self_.thread_dom().contains(thread_ptr));
assert(post1_self_.get_thread(thread_ptr) =~= pre_self_.get_thread(thread_ptr));
assert(post2_self_.get_thread(thread_ptr) =~= pre_self_.get_thread(thread_ptr));
assert(post1_self_.get_thread(thread_ptr).owning_container == oc);
assert(post2_self_.get_thread(thread_ptr).owning_container == oc);

// The freshly-installed thread at `page_ptr_2` is pinned identically.
assert(post1_self_.get_thread(page_ptr_2).owning_container == oc);
assert(post2_self_.get_thread(page_ptr_2).owning_container == oc);
assert(post1_self_.get_thread(page_ptr_2).endpoint_descriptors@
       =~= Seq::new(MAX_NUM_ENDPOINT_DESCRIPTORS as nat, |i: int| { None })
              .update(0, Some(ep_ptr)));
assert(post2_self_.get_thread(page_ptr_2).endpoint_descriptors@
       =~= Seq::new(MAX_NUM_ENDPOINT_DESCRIPTORS as nat, |i: int| { None })
              .update(0, Some(ep_ptr)));
assert(post1_self_.get_thread(page_ptr_2).endpoint_descriptors@
       =~= post2_self_.get_thread(page_ptr_2).endpoint_descriptors@);

// --- Containers: every container other than `oc` is preserved. ---------
// Use the explicit `#![trigger post1_self_.get_container(c_ptr)]` /
// `#![trigger post2_self_.get_container(c_ptr)]` trigger on each run.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != oc
    implies post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
         && post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
         && post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post2_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_thread(thread_ptr).owning_container == oc);
    assert(post2_self_.get_thread(thread_ptr).owning_container == oc);
}

// For `oc`, every observable list view is pinned identically.
assert(post1_self_.get_container(oc).owned_procs@
       =~= pre_self_.get_container(oc).owned_procs@.push(page_ptr_1));
assert(post2_self_.get_container(oc).owned_procs@
       =~= pre_self_.get_container(oc).owned_procs@.push(page_ptr_1));
assert(post1_self_.get_container(oc).owned_procs@
       =~= post2_self_.get_container(oc).owned_procs@);

assert(post1_self_.get_container(oc).owned_endpoints@
       =~= pre_self_.get_container(oc).owned_endpoints@);
assert(post2_self_.get_container(oc).owned_endpoints@
       =~= pre_self_.get_container(oc).owned_endpoints@);
assert(post1_self_.get_container(oc).owned_endpoints@
       =~= post2_self_.get_container(oc).owned_endpoints@);

assert(post1_self_.get_container(oc).owned_threads@
       =~= pre_self_.get_container(oc).owned_threads@.insert(page_ptr_2));
assert(post2_self_.get_container(oc).owned_threads@
       =~= pre_self_.get_container(oc).owned_threads@.insert(page_ptr_2));
assert(post1_self_.get_container(oc).owned_threads@
       =~= post2_self_.get_container(oc).owned_threads@);

// --- Endpoints: every endpoint other than `ep_ptr` is preserved. -------
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != ep_ptr
    implies post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr)
         && post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr)
         && post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
}

// For `ep_ptr`, the owning_threads update is identical.
assert(post1_self_.get_endpoint(ep_ptr).owning_threads@
       =~= pre_self_.get_endpoint(ep_ptr).owning_threads@.insert((page_ptr_2, 0)));
assert(post2_self_.get_endpoint(ep_ptr).owning_threads@
       =~= pre_self_.get_endpoint(ep_ptr).owning_threads@.insert((page_ptr_2, 0)));
assert(post1_self_.get_endpoint(ep_ptr).owning_threads@
       =~= post2_self_.get_endpoint(ep_ptr).owning_threads@);

// --- Procs: pin the new proc at `page_ptr_1`, propagate the rest. ------
assert(post1_self_.get_proc(page_ptr_1).pcid == new_pcid);
assert(post2_self_.get_proc(page_ptr_1).pcid == new_pcid);
assert(post1_self_.get_proc(page_ptr_1).ioid.is_Some());
assert(post2_self_.get_proc(page_ptr_1).ioid.is_Some());
assert(post1_self_.get_proc(page_ptr_1).ioid.unwrap() == new_ioid);
assert(post2_self_.get_proc(page_ptr_1).ioid.unwrap() == new_ioid);
assert(post1_self_.get_proc(page_ptr_1).owned_threads@
       =~= Seq::<ThreadPtr>::empty().push(page_ptr_2));
assert(post2_self_.get_proc(page_ptr_1).owned_threads@
       =~= Seq::<ThreadPtr>::empty().push(page_ptr_2));
assert(post1_self_.get_proc(page_ptr_1).owning_container == oc);
assert(post2_self_.get_proc(page_ptr_1).owning_container == oc);

// Other procs — re-fire the "outside uppertree_seq or owned_procs" ensures
// for both runs with explicit triggers.
assert forall|p_ptr: ProcPtr|
    #![trigger pre_self_.proc_dom().contains(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    && (post1_self_.get_proc(page_ptr_1).uppertree_seq@.contains(p_ptr) == false
        || post1_self_.get_container(oc).owned_procs@.contains(p_ptr) == false)
    implies post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr) by {
}
assert forall|p_ptr: ProcPtr|
    #![trigger pre_self_.proc_dom().contains(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    && (post2_self_.get_proc(page_ptr_1).uppertree_seq@.contains(p_ptr) == false
        || post2_self_.get_container(oc).owned_procs@.contains(p_ptr) == false)
    implies post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr) by {
}

// --- Pointwise key-by-key Map equality, then Map::ext_equal -----------
// container_perms: split on `c == oc` vs `c != oc`.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.container_perms@[c_ptr]]
    #![trigger post2_self_.container_perms@[c_ptr]]
    post1_self_.container_perms@.dom().contains(c_ptr)
    implies post1_self_.container_perms@[c_ptr] == post2_self_.container_perms@[c_ptr] by {
    assert(pre_self_.container_perms@.dom().contains(c_ptr));
    assert(post2_self_.container_perms@.dom().contains(c_ptr));
}
assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);

// process_perms: every key in post1's dom is also in post2's; pointwise
// `get_proc` equality follows from the per-proc ensures.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.process_perms@[p_ptr]]
    #![trigger post2_self_.process_perms@[p_ptr]]
    post1_self_.process_perms@.dom().contains(p_ptr)
    implies post1_self_.process_perms@[p_ptr] == post2_self_.process_perms@[p_ptr] by {
    assert(post2_self_.process_perms@.dom().contains(p_ptr));
}
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);

// thread_perms.
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.thread_perms@[t_ptr]]
    #![trigger post2_self_.thread_perms@[t_ptr]]
    post1_self_.thread_perms@.dom().contains(t_ptr)
    implies post1_self_.thread_perms@[t_ptr] == post2_self_.thread_perms@[t_ptr] by {
    assert(post2_self_.thread_perms@.dom().contains(t_ptr));
}
assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);

// endpoint_perms.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.endpoint_perms@[e_ptr]]
    #![trigger post2_self_.endpoint_perms@[e_ptr]]
    post1_self_.endpoint_perms@.dom().contains(e_ptr)
    implies post1_self_.endpoint_perms@[e_ptr] == post2_self_.endpoint_perms@[e_ptr] by {
    assert(post2_self_.endpoint_perms@.dom().contains(e_ptr));
}
assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);

helper_lemmas:
proof fn lemma_spec_subtract_mem_4k_functional(
    pre: Quota,
    k: usize,
    post1: Quota,
    post2: Quota,
)
    requires
        pre.spec_subtract_mem_4k(post1, k),
        pre.spec_subtract_mem_4k(post2, k),
    ensures
        post1 == post2,
{
    assert(pre.mem_4k - k == post1.mem_4k);
    assert(pre.mem_4k - k == post2.mem_4k);
    assert(post1.mem_4k == post2.mem_4k);
    assert(post1.mem_2m == post2.mem_2m);
    assert(post1.mem_1g == post2.mem_1g);
    assert(post1.pcid == post2.pcid);
    assert(post1.ioid == post2.ioid);
}
